const keyOf = ([x, y]: Cell): string => `${x},${y}`;
const cellFrom = (key: string): Cell => {
  const [x, y] = key.split(",").map(Number);
  return [x, y];
};

const survives = (alive: boolean, neighbors: number): boolean =>
  neighbors === 3 || (alive && neighbors === 2);

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(keyOf));
  const neighborCounts = countNeighbors(cells);
  const next: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    if (survives(liveKeys.has(key), count)) next.push(cellFrom(key));
  }
  return next;
}

function countNeighbors(cells: Cell[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const key = keyOf([x + dx, y + dy]);
      counts.set(key, (counts.get(key) ?? 0) + 1);
    }
  }
  return counts;
}
